package main

import (
	"fmt"
	"net/http"
	"strconv"
	"strings"

	"github.com/google/metrics_api/prometheus/client_golang/prometheus"
	"github.com/google/metrics_api/prometheus/client_golang/promhttp"
)

type userLabelValue struct {
	Name  string
	Value string
}

var (
	requestsTotal = prometheus.NewCounter(prometheus.CounterOpts{
		Name: "request_total",
		Help: "Total number of requests.",
	})

	requestsByUser = make(map[userLabelValue]prometheus.Counter)
	labelsHistogram = prometheus.NewHistogram(prometheus.HistogramOpts{
		Name:    "request_duration_seconds",
		Help:    "Histogram of request durations.",
		Buckets: prometheus.ExponentialBuckets(0.0001, 2, 10),
	})
)

func init() {
	prometheus.MustRegister(requestsTotal)
}

func handler(w http.ResponseWriter, r *http.Request) {
	userLabel := userLabelValue{Name: "user", Value: r.URL.Query().Get("user")}

	if userLabel.Value == "" {
		userLabel.Value = "unknown"
	}

	requestsTotal.Inc()
	requestsByUser[userLabel].Inc()

	start := time.Now()
	// Simulate some work (e.g., database query) here.
	for i := 0; i < 100; i++ {
		fmt.Println("Simulating work...")
	}
	duration := time.Since(start).Seconds()
	labelsHistogram.Observe(duration)

	w.Write([]byte("Hello, World!"))
}

func main() {
	http.HandleFunc("/", handler)
	port := ":8080"
	fmt.Printf("Starting server on port %s...\n", port)
	if err := http.ListenAndServe(port, promhttp.Handler()); err != nil {
		panic(err)
	}
}